arguments.command:
cat > /tmp/binlog-reader/BinlogReader/Program.cs << 'CSHARPEOF'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===\n");

// Collect all errors and warnings
var errors = new List<(string project, string code, string file, int line, int col, string msg, string subcategory)>();
var warnings = new List<(string project, string code, string file, int line, int col, string msg)>();

build.VisitAllChildren<Error>(e =>
{
    var project = FindParentProject(e);
    errors.Add((project, e.Code ?? "", e.File ?? "", e.LineNumber, e.ColumnNumber, e.Text ?? "", e.Subcategory ?? ""));
});

build.VisitAllChildren<Warning>(w =>
{
    var project = FindParentProject(w);
    warnings.Add((project, w.Code ?? "", w.File ?? "", w.LineNumber, w.ColumnNumber, w.Text ?? "", ""));
});

Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine($"Total warnings: {warnings.Count}\n");

Console.WriteLine("=== ERRORS ===");
foreach (var g in errors.GroupBy(e => e.project))
{
    Console.WriteLine($"\n--- Project: {g.Key} ---");
    foreach (var e in g)
    {
        Console.WriteLine($"  [{e.code}] {e.file}({e.line},{e.col}): {e.msg}");
        if (!string.IsNullOrEmpty(e.subcategory))
            Console.WriteLine($"    Subcategory: {e.subcategory}");
    }
}

Console.WriteLine("\n=== WARNINGS ===");
foreach (var g in warnings.GroupBy(w => w.project))
{
    Console.WriteLine($"\n--- Project: {g.Key} ---");
    foreach (var w in g)
    {
        Console.WriteLine($"  [{w.code}] {w.file}({w.line},{w.col}): {w.msg}");
    }
}

// Show project dependency structure
Console.WriteLine("\n=== PROJECT STRUCTURE ===");
build.VisitAllChildren<Project>(p =>
{
    Console.WriteLine($"Project: {Path.GetFileName(p.ProjectFile)} (Succeeded={p.Succeeded})");
});

static string FindParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p)
            return Path.GetFileName(p.ProjectFile ?? "unknown");
        if (current is Target t && t.Project != null)
            return Path.GetFileName(t.Project.ProjectFile ?? "unknown");
        current = current.Parent;
    }
    return "(unknown)";
}
