{
    Console.WriteLine($"  {Path.GetFileName(p.ProjectFile)}: Succeeded={p.Succeeded}");
});

static string FindProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p)
            return Path.GetFileName(p.ProjectFile ?? "?");
        if (current is Target t && t.Project != null)
            return Path.GetFileName(t.Project.ProjectFile ?? "?");
        current = current.Parent;
    }
    return "?";
}
