using SLProject = Microsoft.Build.Logging.StructuredLogger.Project;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== ERRORS ===");
build.VisitAllChildren<Error>(e =>
{
    var proj = FindProject(e);
    Console.WriteLine($"  [{proj}] {e.Code}: {e.File}({e.LineNumber},{e.ColumnNumber})");
    Console.WriteLine($"    {e.Text}");
});

Console.WriteLine();
Console.WriteLine("=== PACKAGE REFERENCES (with metadata) ===");
build.VisitAllChildren<AddItem>(ai =>
{
    if (ai.Name == "PackageReference")
    {
        var proj = FindProject(ai);
        foreach (var child in ai.Children)
        {
            if (child is Item item)
            {
                Console.Write($"  [{proj}] {item.Text}");
                foreach (var m in item.Children)
                {
                    if (m is Metadata md)
                        Console.Write($" {md.Name}={md.Value}");
                }
                Console.WriteLine();
            }
        }
    }
});

Console.WriteLine();
Console.WriteLine("=== PROJECT REFERENCES ===");
build.VisitAllChildren<AddItem>(ai =>
{
    if (ai.Name == "ProjectReference")
    {
        var proj = FindProject(ai);
        foreach (var child in ai.Children)
        {
            if (child is Item item)
                Console.WriteLine($"  [{proj}] -> {item.Text}");
        }
    }
});

Console.WriteLine();
Console.WriteLine("=== NUGET RESTORE DETAILS ===");
build.VisitAllChildren<Message>(m =>
{
    if (m.Text != null && (m.Text.Contains("Newtonsoft") || m.Text.Contains("NU1101") || m.Text.Contains("PackageReference")))
    {
        Console.WriteLine($"  {m.Text.Substring(0, Math.Min(m.Text.Length, 300))}");
    }
});

Console.WriteLine();
Console.WriteLine("=== LOOKING AT project.assets.json ===");
// Check if Newtonsoft.Json is in any project.assets.json
build.VisitAllChildren<Message>(m =>
{
    if (m.Text != null && m.Text.Contains("Newtonsoft.Json"))
        Console.WriteLine($"  MSG: {m.Text.Substring(0, Math.Min(m.Text.Length, 300))}");
});

// Also check if Api project had errors
Console.WriteLine();
Console.WriteLine("=== API PROJECT ERRORS ===");
build.VisitAllChildren<SLProject>(p =>
{
    if (Path.GetFileName(p.ProjectFile) == "Api.csproj")
    {
        Console.WriteLine($"  Api.csproj found, checking for errors...");
        p.VisitAllChildren<Error>(e =>
        {
            Console.WriteLine($"    {e.Code}: {e.Text}");
        });
        p.VisitAllChildren<Message>(m =>
        {
            if (m.Text != null && (m.Text.Contains("error") || m.Text.Contains("Error") || m.Text.Contains("failed")))
                Console.WriteLine($"    MSG: {m.Text.Substring(0, Math.Min(m.Text.Length, 200))}");
        });
    }
});

static string FindProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is SLProject p)
            return Path.GetFileName(p.ProjectFile ?? "?");
        if (current is Target t && t.Project is SLProject tp)
            return Path.GetFileName(tp.ProjectFile ?? "?");
        current = current.Parent;
    }
    return "?";
}
