using Microsoft.Build.Logging.StructuredLogger;
using SLProject = Microsoft.Build.Logging.StructuredLogger.Project;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== CSC TASK DETAILS ===");
build.VisitAllChildren<Microsoft.Build.Logging.StructuredLogger.Task>(task =>
{
    if (task.Name == "Csc")
    {
        var proj = FindProject(task);
        Console.WriteLine($"\n--- Csc for {proj} ---");
        task.VisitAllChildren<Parameter>(p =>
        {
            if (p.Name == "Sources" || p.Name == "References" || p.Name == "CommandLineArgs")
            {
                Console.WriteLine($"  {p.Name}:");
                foreach (var child in p.Children)
                    if (child is Item item)
                        Console.WriteLine($"    {item.Text}");
            }
        });
        // Also look for CommandLineArguments property
        task.VisitAllChildren<Property>(p =>
        {
            Console.WriteLine($"  Property: {p.Name} = {p.Value?.Substring(0, Math.Min(p.Value?.Length ?? 0, 200))}");
        });
    }
});

// Also check Api project specifically for why it didn't compile
Console.WriteLine("\n=== API PROJECT DETAILS ===");
build.VisitAllChildren<SLProject>(p =>
{
    var name = Path.GetFileName(p.ProjectFile);
    if (name == "Api.csproj")
    {
        // check entry targets
        Console.WriteLine($"  Api.csproj entry: {string.Join(",", p.EntryTargets ?? Array.Empty<string>())}");
        p.VisitAllChildren<Error>(e => Console.WriteLine($"  ERROR: {e.Code}: {e.Text}"));
        p.VisitAllChildren<Message>(m =>
        {
            if (m.Text != null && (m.Text.Contains("MSB4181") || m.Text.Contains("failed") || m.Text.Contains("not build")))
                Console.WriteLine($"  MSG: {m.Text.Substring(0, Math.Min(m.Text.Length, 300))}");
        });
    }
});

static string FindProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is SLProject p)
            return Path.GetFileName(p.ProjectFile ?? "?");
        if (current is Target t && t.Project is SLProject tp)
            return Path.GetFileName(tp.ProjectFile ?? "?");
        current = current.Parent;
    }
    return "?";
}
