{
    if (task.Name == "Csc")
    {
        var proj = FindProject(task);
        Console.WriteLine($"\n--- {proj} ---");

        // Dump all children recursively
        void DumpChildren(BaseNode node, int depth)
        {
            if (depth > 4) return;
            var indent = new string(' ', depth * 2);
            foreach (var child in node.Children)
            {
                if (child is Parameter p && (p.Name == "Sources"))
